// F004 cost-cap + F003 sanitize
const input = items[0]?.json?.body || items[0]?.json || {};
const MAX_GOAL=2000, MAX_AUDIENCE=2000;
const sanitize = (s, max) => String(s||'').slice(0,max).replace(/[\u0000-\u001f\u007f]/g,'');
const brief = {
  goal: sanitize(input.goal || 'Aumentare installazioni AdOff su browser desktop nei prossimi 30 giorni minimizzando il costo per install', MAX_GOAL),
  timeframe: sanitize(input.timeframe || 'next 30 days', 100),
  target_audience: sanitize(input.target_audience || 'utenti 25-45 anni infastiditi da pubblicità invasiva, attenti privacy, usano browser desktop quotidianamente', MAX_AUDIENCE),
  budget_note: sanitize(input.budget_note || 'budget bassissimo, leva organico + community + earned media', 500),
  channels_hint: (Array.isArray(input.channels_hint) ? input.channels_hint : ['organic_social','community','content_seo','press','referral']).slice(0,10).map(c=>sanitize(c,40)),
  lang: /^[a-z]{2,5}$/i.test(input.lang) ? input.lang : 'it',
  constraints: sanitize(input.constraints || 'no brand famosi, no claim medici/finanziari, voice energica/brillante', 500)
};
return [{ json: brief }];

const b = $json;
const LANG_NAMES = { it:'italiano', en:'English', de:'Deutsch', fr:'français', es:'español' };
const langName = LANG_NAMES[b.lang] || b.lang;
const schema = JSON.stringify({
  executive_summary: 'string',
  positioning_one_liner: 'string',
  target_personas: [{ name:'string', demographic:'string', pain:'string', hook:'string' }],
  channels: [{ name:'string', why:'string', weekly_actions: ['string'], kpis:['string'] }],
