DELIVERABLE: piano azionabile + calendar di 30 giorni (1 entry/giorno con channel, asset_type es. post/email/video, theme, hook 1 frase, copy_brief 1-2 frasi).

3-5 target_personas. 3-5 channels con weekly_actions concreti (non generici).

RESTITUISCI SOLO JSON VALIDO (no markdown fences):
${schema}`;
return [{ json: { ...b, prompt, model:'gemini-2.5-pro' } }];

function normalizeForGuard(s) {
  if (!s) return '';
  return String(s)
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .toLowerCase()
    .replace(/[·•​-‍﻿⁠]/g, '')
    .replace(/\s+/g, ' ');
}
function brandGuardCheck(rawText) {
  const t = normalizeForGuard(rawText);
  const BRANDS = ['youtube','you tube','y-tube','y tube','google','g00gle','gооgle','facebook','face book','instagram','insta gram','tiktok','tik tok','tik-tok','twitter','\bx\b','amazon','reddit','twitch','github','linkedin','chrome','firefox','safari','microsoft edge','opera'];
  for (const b of BRANDS) {
    const rx = new RegExp(b.replace(/\\b/g,'(?:^|[^\\p{L}\\p{N}])').replace(/\\s+/g,'\\s*'),'iu');
    if (rx.test(t)) return { ok:false, hit:b };
  }
  const SIZE = /149[\s\-_]*k(?:ilo)?b(?:yte)?s?/iu;
  if (SIZE.test(t)) return { ok:false, hit:'149kb' };
  const BANNED_TERMS = /\b(15[\s\-]?day|trial|paid plan|subscription|sottoscrizione|abbonamento|pricing|euro\/mese)/iu;
  if (BANNED_TERMS.test(t)) return { ok:false, hit:'pricing_term' };
  return { ok:true };
}

const meta = $('Build strategist prompt').item.json;
const resp = $json;
let text=''; try { text = resp.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e){}
let parsed=null;
try { parsed = JSON.parse(text); } catch(e) { const m=text.match(/\{[\s\S]*\}/); if(m){ try{parsed=JSON.parse(m[0]);}catch(e2){} } }
if (!parsed || !parsed.executive_summary) return [{ json: { ...meta, ok:false, reason:'gemini_no_valid_json', raw:text.slice(0,400) } }];
const full = JSON.stringify(parsed);
const guard = brandGuardCheck(full);
if (!guard.ok) return [{ json: { ...meta, ok:false, reason:'brand_guard_'+guard.hit, preview:full.slice(0,300) } }];
return [{ json: { ...meta, ok:true, body_json: full, tokens_in: resp.usageMetadata?.promptTokenCount||0, tokens_out: resp.usageMetadata?.candidatesTokenCount||0, calendar_size:(parsed.calendar||[]).length, n_personas:(parsed.target_personas||[]).length, n_channels:(parsed.channels||[]).length } }];

// HMAC-SHA256 Webhook Authentication (inline)
// Validates X-AdOff-Signature header against raw body
// Returns ok:true + extracted payload, or blocks with 401

const crypto = require('crypto');
const secret = process.env.WEBHOOK_HMAC_SECRET;

if (!secret) {
  throw new Error('WEBHOOK_HMAC_SECRET not configured');
}

// Extract signature from headers
const signature = $json.$headers?.['x-adoff-signature'] || $json.headers?.['x-adoff-signature'];
const body = $json.$body || $json.body || JSON.stringify($json);

// In DEV_MODE (env), skip check
if (process.env.DEV_MODE === 'true') {
  return [{ json: { ...($json.body || $json), __hmac_skipped: true } }];
}

if (!signature) {
  return [{ json: { __hmac_error: 'missing_signature_header', statusCode: 401 } }];
}

// Calculate expected HMAC
let bodyForHmac = body;
if (typeof body === 'object') {
  bodyForHmac = JSON.stringify(body);
}

const expectedHmac = crypto
  .createHmac('sha256', Buffer.from(secret, 'hex'))
  .update(bodyForHmac, 'utf8')
  .digest('hex');

// Timing-safe comparison
try {
  crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedHmac, 'hex')
  );
  // Valid signature: continue with payload
  return [{ json: { ...($json.body || $json), __hmac_validated: true } }];
} catch (err) {
  return [{ json: { __hmac_error: 'invalid_signature', statusCode: 401 } }];
}
